struct Node {
    int val; 
    Node *left;
    Node *right;

    Node(int node_value) {
        val = node_value;
        left = right = NULL;
    }
}; */

class Solution {
    int checkHeight(Node* root) {
        // Base case
        if (root == NULL)  
           return 0;

        // Height of left subtree
        int left_height = checkHeight(root->left);

        // Height of right subtree
        int right_height = checkHeight(root->right);

        // In case of left subtree or right subtree unbalanced, return -1
        if (left_height == -1 || right_height == -1)  
           return -1;

        // If their heights differ by more than 1, return -1
        if (abs(left_height - right_height) > 1)  
           return -1;

        // Otherwise, return the height of this subtree as 1 +  max(leftHeight, 1 rightHeight)
        return 1 + max(left_height, right_height);
    }
  public:
    void isHeightBalanced(Node* root) {
        // If the tree is empty, we can say it’s balanced
        if (root == NULL) { 
           cout << "YES";
           return;
        }
        // checkHeight function will return -1, when it’s an unbalanced tree
        if (checkHeight(root) == -1)  {
           cout << "NO";
        } else {
           cout << "YES";
        }
    }
};

